subprograms.code:
PROCEDURE Decode
 (src      : System.Address;
  srclen   : Integer;
  dst      : System.Address;
  dstsize  : Integer;
  dstlen   : OUT Integer;
  error    : OUT Integer)

PROCEDURE Encode
 (src      : System.Address;
  srclen   : Integer;
  dst      : System.Address;
  dstsize  : Integer;
  dstlen   : OUT Integer;
  error    : OUT Integer)

PROCEDURE Receive
 (fd       : Integer;
  dst      : System.Address;
  dstsize  : Integer;
  dstlen   : IN OUT Integer;
  error    : OUT Integer)

PROCEDURE Send
 (fd       : Integer;
  src      : System.Address;
  srclen   : Integer;
  sent     : OUT Integer;
  error    : OUT Integer)
